            // `total_count` messages. Criterion wants total time
            // for `iters` iterations, so project linearly.
            let per_msg_ns = measurement.as_nanos() as u64 / total_count.max(1);
            Duration::from_nanos(per_msg_ns.saturating_mul(iters))
        });
    });
    group.finish();
}

