    /// for popped buffers, slots `0..size` retain whatever
    /// bytes the previous occupant wrote (no zeroing — see
    /// module docs).
    pub fn get_msg(&self, size: usize) -> PooledMsg {
        assert!(
            size <= MAX_SIZE,
            "size {size} exceeds MAX_SIZE {MAX_SIZE}"
        );
        let popped = {
            #[allow(clippy::unwrap_used)]
            // OK: Mutex only poisoned by a panic while locked; the
            //   pool's lock holders only push/pop, no panic path.
            let mut free = self.inner.free.lock().unwrap();
            free.pop()
        };
        let mut buf = popped.unwrap_or_else(|| Vec::with_capacity(MAX_SIZE)); // OK: empty pool → fresh MAX_SIZE-capacity allocation
        buf.resize(size, 0);
        PooledMsg {
            buf: Some(buf),
            pool: self.inner.clone(),
        }
    }

    /// Number of buffers currently sitting in the free list.
    /// Useful for tests; not for production logic.
    #[cfg(test)]
    pub(crate) fn free_len(&self) -> usize {
        #[allow(clippy::unwrap_used)]
        // OK: see Pool::get_msg for poisoning rationale.
        self.inner.free.lock().unwrap().len()
    }
}

impl Default for Pool {
    /// Same as [`Pool::new`].
    fn default() -> Self {
        Self::new()
    }
}

/// Owned byte buffer handed out by a [`Pool`]. Implements
/// [`Deref`] / [`DerefMut`] over `[u8]` so handlers can take
/// `&*msg` for an `&[u8]` view (or `&mut *msg` for `&mut [u8]`).
/// On `Drop`, the buffer returns to its originating pool's
/// free list rather than being freed.
pub struct PooledMsg {
    buf: Option<Vec<u8>>,
    pool: Arc<PoolInner>,
}

impl Deref for PooledMsg {
    type Target = [u8];
    /// Borrow the buffer's contents as an `&[u8]` of length
    /// `size` (the value passed to [`Pool::get_msg`]).
    fn deref(&self) -> &[u8] {
        #[allow(clippy::unwrap_used)]
        // OK: `buf` is only `None` between `Drop::drop`'s `take`
        //   and the end of `drop`; `Deref` cannot run during that
        //   window.
        self.buf.as_ref().unwrap()
    }
}

impl DerefMut for PooledMsg {
    /// Mutably borrow the buffer as `&mut [u8]`.
    fn deref_mut(&mut self) -> &mut [u8] {
        #[allow(clippy::unwrap_used)]
        // OK: see `Deref::deref`.
        self.buf.as_mut().unwrap()
    }
}

impl Drop for PooledMsg {
    /// Return the underlying `Vec<u8>` to the pool's free
    /// list. The buffer's `len()` is whatever the occupant
    /// last left it at; the next `get_msg(size)` consumer
    /// resizes to its requested length.
    fn drop(&mut self) {
        if let Some(buf) = self.buf.take() {
            #[allow(clippy::unwrap_used)]
            // OK: see Pool::get_msg for poisoning rationale.
            self.pool.free.lock().unwrap().push(buf);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// `get_msg(size)` returns a buffer of length `size`.
    #[test]
    fn get_msg_returns_requested_size() {
        let p = Pool::new();
        let m = p.get_msg(16);
        assert_eq!(m.len(), 16);
    }

    /// Boundary: `size == MAX_SIZE` is allowed.
    #[test]
    fn get_msg_at_max_size_ok() {
        let p = Pool::new();
        let m = p.get_msg(MAX_SIZE);
        assert_eq!(m.len(), MAX_SIZE);
    }

    /// Boundary: `size == 0` is allowed and yields an empty
    /// slice. Cheap to allow; no reason to forbid.
    #[test]
    fn get_msg_zero_size_ok() {
        let p = Pool::new();
        let m = p.get_msg(0);
        assert_eq!(m.len(), 0);
    }

    /// `size > MAX_SIZE` panics (caller-side bug).
    #[test]
    #[should_panic(expected = "exceeds MAX_SIZE")]
    fn get_msg_over_max_panics() {
        let p = Pool::new();
        let _ = p.get_msg(MAX_SIZE + 1);
    }

    /// Dropping a `PooledMsg` returns its buffer to the pool.
    #[test]
    fn drop_returns_buffer_to_pool() {
        let p = Pool::new();
        assert_eq!(p.free_len(), 0);
        let m = p.get_msg(8);
        assert_eq!(p.free_len(), 0);
        drop(m);
        assert_eq!(p.free_len(), 1);
    }

    /// After drop+reacquire, the same backing allocation is
    /// reused (pointer equality holds because `Vec::with_capacity`
    /// + `resize` within capacity does not reallocate).
    #[test]
    fn buffer_is_reused_across_get_drop_get() {
        let p = Pool::new();
        let m1 = p.get_msg(8);
        let ptr1 = m1.as_ptr();
        drop(m1);
        let m2 = p.get_msg(16);
        assert_eq!(m2.as_ptr(), ptr1, "expected reuse of the same allocation");
        assert_eq!(m2.len(), 16);
    }

    /// Cloned `Pool` handles share the same free list.
    #[test]
    fn clone_pool_shares_free_list() {
        let p1 = Pool::new();
        let p2 = p1.clone();
        drop(p1.get_msg(8));
        assert_eq!(p2.free_len(), 1);
    }

    /// Writes through `DerefMut` round-trip via `Deref`.
    #[test]
    fn writes_round_trip() {
        let p = Pool::new();
        let mut m = p.get_msg(4);
        m.copy_from_slice(&[1, 2, 3, 4]);
        assert_eq!(&*m, &[1, 2, 3, 4]);
    }

    /// Sharing a pool across threads is sound; buffers dropped
    /// on a worker thread return to the same free list visible
    /// from the main thread.
    #[test]
    fn pool_works_across_threads() {
        use std::thread;
        let p = Pool::new();
        let p2 = p.clone();
        let h = thread::spawn(move || {
            let m = p2.get_msg(8);
            drop(m);
        });
        h.join().expect("worker thread panicked");
        assert_eq!(p.free_len(), 1);
    }
}

