//! Fixed-capacity buffer pool for `RuntimeZC` zerocopy messages.
//!
//! A [`Pool`] is configured at construction with `msg_size` (the
//! maximum byte length of any buffer it hands out) and
//! `msg_count` (the number of buffers it pre-allocates). Its
//! free list never grows beyond `msg_count`: once all buffers
//! are in flight, [`Pool::get_msg`] returns
//! [`PoolError::NoMsgs`]. Requests for a size greater than the
//! pool's `msg_size` return [`PoolError::SizeTooLarge`]. Buffers
//! return to the free list when their owning [`PooledMsg`] is
//! dropped.
//!
//! Storage is `Arc<Mutex<Vec<Vec<u8>>>>` — simple, some lock
//! contention under multi-thread load. A lock-free upgrade
//! (e.g. `crossbeam_queue::ArrayQueue`) is deferred until
//! `goalzc` shows the contention cost matters.
//!
//! No zeroing happens on drop. A reused buffer's bytes
//! `0..new_size` may contain residual data from the previous
//! occupant; ping-pong handlers either overwrite or ignore
//! those bytes, so the leak is benign for the workloads this
//! crate measures. Real applications that ship pooled messages
//! between trust domains would need an explicit zeroize step.

use std::ops::{Deref, DerefMut};
use std::sync::{Arc, Mutex};

/// Failure modes for [`Pool::get_msg`].
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum PoolError {
    /// The requested size exceeds the pool's configured
    /// `msg_size`. `requested` is what the caller asked for;
    /// `max` is the pool's `msg_size`.
    SizeTooLarge { requested: usize, max: usize },
    /// Every buffer the pool owns is currently in flight as a
    /// live [`PooledMsg`]. Caller must wait for a drop or
    /// increase `msg_count` when constructing the pool.
    NoMsgs,
}

impl std::fmt::Display for PoolError {
    /// Render a human-readable one-liner for logs / panics.
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            PoolError::SizeTooLarge { requested, max } => {
                write!(f, "requested size {requested} exceeds pool msg_size {max}")
            }
            PoolError::NoMsgs => f.write_str("pool exhausted: all buffers are in flight"),
        }
    }
}

impl std::error::Error for PoolError {}

/// Internal pool storage; held by `Arc` so actor threads share
/// one free list. Keep this private — callers see only [`Pool`]
/// and [`PooledMsg`].
struct PoolInner {
    msg_size: usize,
    free: Mutex<Vec<Vec<u8>>>,
}

/// Cheaply-cloneable handle to a shared, fixed-capacity buffer
/// pool. Clones share the same free list (internally `Arc`).
#[derive(Clone)]
pub struct Pool {
    inner: Arc<PoolInner>,
}

impl Pool {
    /// Build a pool that pre-allocates `msg_count` buffers,
    /// each with capacity `msg_size` bytes. Both are `u32` so
    /// the pool's total footprint is bounded at the type
    /// level at `u32::MAX * u32::MAX` bytes, well beyond any
    /// realistic usage.
    ///
    /// `msg_count == 0` is allowed — the pool immediately
    /// returns [`PoolError::NoMsgs`] on every `get_msg` call,
    /// useful for exhaustion tests.
    pub fn new(msg_size: u32, msg_count: u32) -> Self {
        let msg_size = msg_size as usize;
        let msg_count = msg_count as usize;
        let mut free = Vec::with_capacity(msg_count);
        for _ in 0..msg_count {
            free.push(Vec::with_capacity(msg_size));
        }
        Self {
            inner: Arc::new(PoolInner {
                msg_size,
                free: Mutex::new(free),
            }),
        }
    }

    /// The pool's configured maximum message size in bytes.
    /// Callers use this to validate requests up-front or size
    /// their outbound messages.
    pub fn msg_size(&self) -> u32 {
        self.inner.msg_size as u32
    }

    /// Take a buffer of logical length `size` from the pool.
    /// Returns [`PoolError::SizeTooLarge`] if
    /// `size > msg_size`, or [`PoolError::NoMsgs`] if every
    /// buffer is currently in flight.
    ///
    /// Popped buffers retain whatever bytes the previous
    /// occupant wrote (no zeroing — see module docs); the
    /// slice's logical length is exactly `size`.
    pub fn get_msg(&self, size: usize) -> Result<PooledMsg, PoolError> {
        if size > self.inner.msg_size {
            return Err(PoolError::SizeTooLarge {
                requested: size,
                max: self.inner.msg_size,
            });
        }
        let popped = {
            #[allow(clippy::unwrap_used)]
            // OK: Mutex only poisoned by a panic while locked; the
            //   pool's lock holders only push/pop, no panic path.
            let mut free = self.inner.free.lock().unwrap();
            free.pop()
        };
        let mut buf = popped.ok_or(PoolError::NoMsgs)?;
        buf.resize(size, 0);
        Ok(PooledMsg {
            buf: Some(buf),
            pool: self.inner.clone(),
        })
    }

    /// Number of buffers currently sitting in the free list.
    /// Useful for tests; not for production logic.
    #[cfg(test)]
    pub(crate) fn free_len(&self) -> usize {
        #[allow(clippy::unwrap_used)]
        // OK: see Pool::get_msg for poisoning rationale.
        self.inner.free.lock().unwrap().len()
    }
}

/// Owned byte buffer handed out by a [`Pool`]. Implements
/// [`Deref`] / [`DerefMut`] over `[u8]` so handlers can take
/// `&*msg` for an `&[u8]` view (or `&mut *msg` for `&mut [u8]`).
/// On `Drop`, the buffer returns to its originating pool's
/// free list rather than being freed.
pub struct PooledMsg {
    buf: Option<Vec<u8>>,
    pool: Arc<PoolInner>,
}

impl Deref for PooledMsg {
