//! Fixed-capacity buffer pool for `RuntimeZC` zerocopy messages.
//!
//! A [`Pool`] is configured at construction with `msg_size` (the
//! maximum byte length of any buffer it hands out) and
//! `msg_count` (the number of buffers it pre-allocates). The
//! pool's free list is held in a [`BufRefStore`] implementation;
//! swapping implementations is how this crate will benchmark
//! different concurrency strategies (Mutex, lock-free queue,
//! ring buffer, hand-rolled atomics, …). The default is
//! [`MutexLifo`].
//!
//! Retrieval order is implementation-defined — callers treat
//! buffers as fungible. [`Pool::get_msg`] returns either a
//! [`PooledMsg`] (a fixed-size `Box<[u8]>` that derefs to
//! `[u8]`) or a [`PoolError`]: [`PoolError::SizeTooLarge`] if
//! the requested size exceeds `msg_size`, or
//! [`PoolError::NoMsgs`] if the store is currently empty.
//! Buffers return to the store when their owning `PooledMsg` is
//! dropped.
//!
//! No zeroing happens on drop. A reused buffer's bytes
//! `0..new_size` may contain residual data from the previous
//! occupant; ping-pong handlers either overwrite or ignore
//! those bytes, so the leak is benign for the workloads this
//! crate measures. Real applications that ship pooled messages
//! between trust domains would need an explicit zeroize step.
//!
//! Future extension (not yet implemented): once `Pool` supports
//! multiple size classes — small / medium / large sub-pools so
//! the many-small-few-large case is cheap — a single `Pool`
//! will hold several `BufRefStore` instances, one per class.
//! `BufRefStore::size()` on each still returns that sub-store's
//! capacity; [`Pool::size`] sums across them for the total.

use std::ops::{Deref, DerefMut};
use std::sync::{Arc, Mutex};

/// Nullable buffer handle. Concretely `Option<Box<[u8]>>`, which
/// thanks to Rust's niche optimization occupies exactly one
/// pointer at runtime — `None` is the null bit pattern,
/// `Some(box)` is the non-null heap address of a fixed-size
/// byte allocation. Used wherever the code needs to express
/// "a buffer, or nothing":
/// - inside [`PooledMsg`] so [`Drop::drop`] can [`Option::take`]
///   the box out without leaving `self` in an invalid state;
/// - as [`BufRefStore::get`]'s return value so stores can
///   signal "empty".
pub type BufRef = Option<Box<[u8]>>;

/// Failure modes for [`Pool::get_msg`].
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum PoolError {
    /// The requested size exceeds the pool's configured
    /// `msg_size`. `requested` is what the caller asked for;
    /// `max` is the pool's `msg_size`.
    SizeTooLarge { requested: usize, max: usize },
    /// Every buffer the pool owns is currently in flight as a
    /// live [`PooledMsg`]. Caller must wait for a drop or build
    /// a pool with more `msg_count`.
    NoMsgs,
}

impl std::fmt::Display for PoolError {
    /// Render a human-readable one-liner for logs / panics.
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            PoolError::SizeTooLarge { requested, max } => {
                write!(f, "requested size {requested} exceeds pool msg_size {max}")
            }
            PoolError::NoMsgs => f.write_str("pool exhausted: all buffers are in flight"),
        }
    }
}

impl std::error::Error for PoolError {}

/// Thread-safe storage backend for a [`Pool`]'s free list.
/// Implementations choose the retrieval order (LIFO, FIFO,
/// ring-buffer, …); `Pool` treats the stored buffers as
/// fungible and does not depend on any particular ordering.
///
/// Swapping implementations is the primary extension point
/// for benchmarking different concurrency strategies. See
/// [`MutexLifo`] for the default.
pub trait BufRefStore: Send + Sync {
    /// Build a store that takes ownership of the given
    /// pre-allocated buffers. The store's capacity
    /// ([`BufRefStore::size`]) equals `buffers.len()`; its
    /// initial [`BufRefStore::len`] also equals `buffers.len()`
    /// — the store starts full.
    fn from_buffers(buffers: Vec<Box<[u8]>>) -> Self
    where
        Self: Sized;

    /// Retrieve one buffer from the store, or `None` if the
    /// store is currently empty.
    fn get(&self) -> BufRef;

    /// Return a buffer to the store. Precondition: total `ret`
    /// calls must never exceed total `get` calls plus the
    /// store's initial capacity. Violating this panics in
    /// well-behaved implementations.
    fn ret(&self, buf: Box<[u8]>);

    /// Current number of buffers held by the store. Under
    /// concurrent load the value is best-effort — it may be
    /// stale by the time a caller reads it — but it is always
    /// a valid count (never torn, never beyond `size()`).
    fn len(&self) -> usize;

    /// Maximum capacity of the store — the count of buffers
    /// handed to [`BufRefStore::from_buffers`]. Constant for
    /// the lifetime of the store.
    fn size(&self) -> usize;

    /// `len() == 0`. Provided as a default; impls can override
    /// with a faster path if their `len()` is not already O(1).
    fn is_empty(&self) -> bool {
        self.len() == 0
    }
}

/// Mutex-protected `Vec`-backed LIFO store. The default
/// [`BufRefStore`] implementation: simple, correct, and
/// easy to reason about; a baseline to benchmark future
/// lock-free alternatives against.
///
/// `Vec`'s `push` / `pop` give LIFO order at microsecond-ish
/// cost per op (lock acquire + vector push-or-pop). The
/// `Vec`'s capacity never changes after `from_buffers` because
/// `ret` is guaranteed to be matched by a prior `get`.
pub struct MutexLifo {
    inner: Mutex<Vec<Box<[u8]>>>,
    /// Cached at construction so `size()` is O(1) and
    /// lock-free.
    size: usize,
}

impl BufRefStore for MutexLifo {
    /// Take ownership of `buffers` behind a `Mutex`. `size` is
    /// recorded once here and never changes.
    fn from_buffers(buffers: Vec<Box<[u8]>>) -> Self {
        let size = buffers.len();
        Self {
            inner: Mutex::new(buffers),
            size,
        }
    }

    /// LIFO `pop` from the free list; `None` when empty.
    fn get(&self) -> BufRef {
        #[allow(clippy::unwrap_used)]
        // OK: Mutex only poisoned by a panic while locked; the
        //   store's lock holders only push / pop / len / capacity,
        //   none of which panic.
        self.inner.lock().unwrap().pop()
    }

    /// LIFO `push` back onto the free list.
    fn ret(&self, buf: Box<[u8]>) {
        #[allow(clippy::unwrap_used)]
        // OK: see MutexLifo::get.
        self.inner.lock().unwrap().push(buf);
    }

    /// Current count of buffers sitting in the free list.
    fn len(&self) -> usize {
        #[allow(clippy::unwrap_used)]
        // OK: see MutexLifo::get.
        self.inner.lock().unwrap().len()
    }

    /// Maximum capacity — fixed at construction.
    fn size(&self) -> usize {
        self.size
    }
}

/// Internal pool storage; held by `Arc` so actor threads share
/// one free list. Keep this private — callers see only
/// [`Pool`] and [`PooledMsg`].
struct PoolInner<S: BufRefStore> {
    msg_size: usize,
    free: S,
}

/// Cheaply-cloneable handle to a shared, fixed-capacity buffer
/// pool. Clones share the same free list (internally `Arc`).
///
/// The `S` type parameter selects the underlying
/// [`BufRefStore`] implementation; it defaults to
/// [`MutexLifo`] so ordinary callers write `Pool::new(64, 128)`
/// without annotations. Benchmarks opt in to a different
/// backend via `Pool::<SomeOtherStore>::new(64, 128)`.
pub struct Pool<S: BufRefStore = MutexLifo> {
    inner: Arc<PoolInner<S>>,
}

// Manual `Clone` — `#[derive(Clone)]` would add a spurious
// `S: Clone` bound, but `Arc<T>` is always clone regardless of T.

